import { useState, useEffect } from 'react'
import { useSearchParams } from 'react-router-dom'
import { customersAPI } from '../../services/api'
import { toast } from 'react-hot-toast'
import { Camera, Upload, X, Save, UserPlus, ArrowLeft, Calendar, ChevronDown, AlertCircle } from 'lucide-react'
import CustomerServiceSection from '../../components/CustomerServiceSection'

const CustomerAdd = () => {
  const [searchParams] = useSearchParams()
  const editId = searchParams.get('edit')
  const [loading, setLoading] = useState(false)
  const [editingCustomer, setEditingCustomer] = useState(null)
  const [selectedPhoto, setSelectedPhoto] = useState(null)
  const [photoPreview, setPhotoPreview] = useState(null)
  const [showConfirmDialog, setShowConfirmDialog] = useState(false)
  const [pendingSubmit, setPendingSubmit] = useState(null)
  const [formData, setFormData] = useState({
    customerId: '',
    name: '',
    fatherName: '',
    motherName: '',
    dateOfBirth: '',
    address: '',
    pincode: '',
    cellNo: '',
    emailId: '',
    refer: '',
    referName: '',
    aadhaarNumber: '',
    panCardNumber: '',
    rationCardNumber: '',
    voterIdNumber: '',
    otherIdDetails: '',
    service: '',
    subService: '',
    staff: ''
  })
  const [dobError, setDobError] = useState('')
  const [services, setServices] = useState([])
  const [subServices, setSubServices] = useState([])
  const [staff, setStaff] = useState([])
  const [loadingServices, setLoadingServices] = useState(false)
  const [loadingSubServices, setLoadingSubServices] = useState(false)
  const [loadingStaff, setLoadingStaff] = useState(false)

  useEffect(() => {
    if (editId) {
      fetchCustomer(editId)
    } else {
      generateCustomerId()
    }
    // Load services and staff data
    fetchServices()
    fetchStaff()
  }, [editId])

  const fetchCustomer = async (id) => {
    try {
      setLoading(true)
      const response = await customersAPI.getById(id)
      const customer = response.data
      setEditingCustomer(customer)
      
      const serviceId = customer.service?._id || customer.service || ''
      const subServiceId = customer.subService?._id || customer.subService || ''
      
      setFormData({
        customerId: customer.customerId,
        name: customer.name,
        fatherName: customer.fatherName,
        motherName: customer.motherName || '',
        dateOfBirth: customer.dateOfBirth ? formatDobInput(new Date(customer.dateOfBirth).toLocaleDateString('en-GB')) : '',
        address: customer.address,
        pincode: customer.pincode,
        cellNo: customer.cellNo,
        emailId: customer.emailId,
        refer: customer.refer || '',
        referName: customer.referName || '',
        aadhaarNumber: customer.aadhaarNumber || '',
        panCardNumber: customer.panCardNumber || '',
        rationCardNumber: customer.rationCardNumber || '',
        voterIdNumber: customer.voterIdNumber || '',
        otherIdDetails: customer.otherIdDetails || '',
        service: serviceId,
        subService: subServiceId,
        staff: customer.staff?._id || customer.staff || ''
      })
      
      // Fetch sub-services for the customer's service
      if (serviceId) {
        await fetchSubServices(serviceId)
      }
    } catch (error) {
      toast.error('Failed to fetch customer details')
      console.error('Error fetching customer:', error)
    } finally {
      setLoading(false)
    }
  }

  const generateCustomerId = async () => {
    try {
      // Fetch all existing customers to determine the next ID
      const response = await customersAPI.getAll()
      const customers = response.data || []
      
      // Find the highest existing customer ID number
      let maxId = -1
      customers.forEach(customer => {
        if (customer.customerId) {
          // Extract numeric part from customer ID (assuming format like "0", "1", "2", etc.)
          const idNum = parseInt(customer.customerId)
          if (!isNaN(idNum) && idNum > maxId) {
            maxId = idNum
          }
        }
      })
      
      // Generate next ID (start from 0 if no customers exist)
      const nextId = maxId + 1
      const customerId = nextId.toString()
      
      setFormData(prev => ({ ...prev, customerId }))
    } catch (error) {
      console.error('Error generating customer ID:', error)
      // Fallback to timestamp-based ID if API fails
      const timestamp = Date.now().toString(36)
      const random = Math.random().toString(36).substr(2, 5)
      const customerId = `CUST-${timestamp}-${random}`.toUpperCase()
      setFormData(prev => ({ ...prev, customerId }))
    }
  }

  const fetchServices = async () => {
    try {
      setLoadingServices(true)
      console.log('Fetching services...')
      const { servicesAPI } = await import('../../services/api')
      const response = await servicesAPI.getAll()
      console.log('Services loaded:', response.data?.length || 0)
      setServices(response.data || [])
    } catch (error) {
      console.error('Error fetching services:', error)
      toast.error('Failed to load services')
      setServices([])
    } finally {
      setLoadingServices(false)
    }
  }

  const fetchSubServices = async (serviceId) => {
    try {
      setLoadingSubServices(true)
      console.log('Fetching sub-services for service:', serviceId)
      const { subServicesAPI } = await import('../../services/api')
      const response = await subServicesAPI.getAll(serviceId)
      console.log('Sub-services loaded:', response.data?.length || 0)
      setSubServices(response.data || [])
    } catch (error) {
      console.error('Error fetching sub-services:', error)
      toast.error('Failed to load sub-services')
      setSubServices([])
    } finally {
      setLoadingSubServices(false)
    }
  }

  const fetchStaff = async () => {
    try {
      setLoadingStaff(true)
      console.log('Fetching staff...')
      const { staffAPI } = await import('../../services/staffAPI')
      const response = await staffAPI.getActive()
      console.log('Staff loaded:', response.data?.length || 0)
      setStaff(response.data || [])
    } catch (error) {
      console.error('Error fetching staff:', error)
      toast.error('Failed to load staff')
      setStaff([])
    } finally {
      setLoadingStaff(false)
    }
  }

  const formatDateToIso = (date) => {
    if (!date) return ''
    if (date instanceof Date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      return `${year}-${month}-${day}`
    }
    // If it's already in ISO format, return as is
    if (date.includes('-')) return date
    return ''
  }

  const formatDobInput = (value) => {
    // Remove all non-digit characters
    const digits = value.replace(/\D/g, '')
    
    // Auto-format as DD/MM/YYYY
    if (digits.length <= 2) {
      return digits
    } else if (digits.length <= 4) {
      return `${digits.slice(0, 2)}/${digits.slice(2)}`
    } else if (digits.length <= 8) {
      return `${digits.slice(0, 2)}/${digits.slice(2, 4)}/${digits.slice(4, 8)}`
    }
    return `${digits.slice(0, 2)}/${digits.slice(2, 4)}/${digits.slice(4, 8)}`
  }

  const convertDdMmYyyyToIso = (ddMmYyyy) => {
    if (!ddMmYyyy) return ''
    const parts = ddMmYyyy.split('/')
    if (parts.length !== 3) return ''
    const [day, month, year] = parts
    if (day.length !== 2 || month.length !== 2 || year.length !== 4) return ''
    
    // Validate date
    const dayNum = parseInt(day)
    const monthNum = parseInt(month)
    const yearNum = parseInt(year)
    
    if (isNaN(dayNum) || isNaN(monthNum) || isNaN(yearNum)) return ''
    if (dayNum < 1 || dayNum > 31) return ''
    if (monthNum < 1 || monthNum > 12) return ''
    if (yearNum < 1900 || yearNum > new Date().getFullYear()) return ''
    
    // Create date object to validate
    const date = new Date(yearNum, monthNum - 1, dayNum)
    if (date.getDate() !== dayNum || date.getMonth() !== monthNum - 1 || date.getFullYear() !== yearNum) {
      return '' // Invalid date (e.g., 31/02/2020)
    }
    
    return `${year}-${month}-${day}`
  }

  const validateDob = (dob) => {
    if (!dob) return 'Date of birth is required'
    if (dob.length !== 10) return 'Please enter complete date (DD/MM/YYYY)'
    
    const isoDate = convertDdMmYyyyToIso(dob)
    if (!isoDate) return 'Please enter a valid date'
    
    // Check if date is not in future
    const enteredDate = new Date(isoDate)
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    if (enteredDate > today) return 'Date of birth cannot be in the future'
    
    return '' // Valid
  }

  
  const handlePhotoChange = (e) => {
    const file = e.target.files[0]
    if (file) {
      setSelectedPhoto(file)
      const reader = new FileReader()
      reader.onloadend = () => {
        setPhotoPreview(reader.result)
      }
      reader.readAsDataURL(file)
    }
  }

  const getImageUrl = (photoPath) => {
    if (!photoPath) return null
    if (photoPath.startsWith('http')) {
      return photoPath
    }
    if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
      return `http://localhost:5001/uploads/${photoPath}`
    } else {
      return `https://two026backend.onrender.com/uploads/${photoPath}`
    }
  }

  const handleImageError = (e) => {
    e.target.style.display = 'none'
    e.target.nextSibling.style.display = 'flex'
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    
    // Validate date of birth before submission
    const dobValidationError = validateDob(formData.dateOfBirth)
    if (dobValidationError) {
      setDobError(dobValidationError)
      toast.error(dobValidationError)
      return
    }
    
    // Show custom confirmation dialog
    setShowConfirmDialog(true)
    setPendingSubmit(() => async () => {
      setLoading(true)
      await performSubmit()
    })
  }

  const performSubmit = async () => {
    try {
      // Convert dateOfBirth from DD/MM/YYYY to ISO format for backend
      const submissionData = {
        ...formData,
        dateOfBirth: formData.dateOfBirth ? convertDdMmYyyyToIso(formData.dateOfBirth) : ''
      }

      let response
      if (editingCustomer) {
        // Update existing customer
        response = await customersAPI.update(editingCustomer._id, submissionData)
        toast.success('Customer updated successfully')
        
        // If we have a selected photo, upload it after updating
        if (selectedPhoto) {
          const photoFormData = new FormData()
          photoFormData.append('photo', selectedPhoto)
          await customersAPI.updatePhoto(editingCustomer._id, photoFormData)
          toast.success('Photo updated successfully')
        }
      } else {
        // Create new customer
        response = await customersAPI.create(submissionData)
        toast.success('Customer created successfully')
        
        // If we have a selected photo, upload it after creating
        if (selectedPhoto && response.data._id) {
          const photoFormData = new FormData()
          photoFormData.append('photo', selectedPhoto)
          await customersAPI.uploadPhoto(response.data._id, photoFormData)
          toast.success('Photo uploaded successfully')
        }
      }

      // Reset form and redirect to customer list
      resetForm()
      window.history.pushState({}, '', '/customer-management?tab=customers')
      window.dispatchEvent(new PopStateEvent('popstate'))
    } catch (error) {
      console.error('Save customer error:', error)
      const errorMessage = error.response?.data?.message || error.message || 'Failed to save customer'
      toast.error(errorMessage)
    } finally {
      setLoading(false)
    }
  }

  const resetForm = () => {
    setFormData({
      customerId: '',
      name: '',
      fatherName: '',
      motherName: '',
      dateOfBirth: '',
      address: '',
      pincode: '',
      cellNo: '',
      emailId: '',
      refer: '',
      referName: '',
      aadhaarNumber: '',
      panCardNumber: '',
      rationCardNumber: '',
      voterIdNumber: '',
      otherIdDetails: '',
      service: '',
      subService: '',
      staff: ''
    })
    setSelectedPhoto(null)
    setPhotoPreview(null)
    setEditingCustomer(null)
    setDobError('')
  }

  const handlePhotoDelete = async () => {
    if (editingCustomer && editingCustomer.photo) {
      if (window.confirm('Are you sure you want to delete this photo?')) {
        try {
          await customersAPI.deletePhoto(editingCustomer._id)
          toast.success('Photo deleted successfully')
          setEditingCustomer(prev => ({ ...prev, photo: null }))
        } catch (error) {
          toast.error('Failed to delete photo')
          console.error('Error deleting photo:', error)
        }
      }
    }
  }

  if (loading && editId) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="h-screen overflow-y-auto max-w-7xl mx-auto">
      {/* Form */}
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Customer Information Section */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
            <span className="w-1 h-6 bg-blue-600 mr-3 rounded"></span>
            Customer Information
          </h3>
          <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
            {/* Customer ID */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Customer ID *
              </label>
              <div className="flex gap-2">
                <input
                  type="text"
                  required
                  value={formData.customerId}
                  onChange={(e) => setFormData({...formData, customerId: e.target.value})}
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  disabled={!!editingCustomer}
                  placeholder={editingCustomer ? "" : "Auto-generated (e.g., 0, 1, 2, ...)"}
                />
                {!editingCustomer && (
                  <button
                    type="button"
                    onClick={generateCustomerId}
                    className="px-3 py-2 bg-blue-500 text-white text-sm rounded-lg hover:bg-blue-600 transition-colors"
                    title="Generate new Customer ID"
                  >
                    🔄
                  </button>
                )}
              </div>
              {!editingCustomer && (
                <p className="text-xs text-gray-500 mt-1">Customer ID will be auto-generated sequentially starting from 0</p>
              )}
            </div>
            
            {/* Name */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Name (Aadhaarcard Name) *
              </label>
              <input
                type="text"
                required
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value.replace(/\b\w/g, l => l.toUpperCase())})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter customer name"
              />
            </div>
            
            {/* Father Name */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Father Name *
              </label>
              <input
                type="text"
                required
                value={formData.fatherName}
                onChange={(e) => setFormData({...formData, fatherName: e.target.value.replace(/\b\w/g, l => l.toUpperCase())})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter father's name"
              />
            </div>
            
            {/* Mother Name */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Mother Name
              </label>
              <input
                type="text"
                value={formData.motherName || ''}
                onChange={(e) => setFormData({...formData, motherName: e.target.value.replace(/\b\w/g, l => l.toUpperCase())})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter mother's name"
              />
            </div>
            
            {/* Date of Birth */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Date of Birth *
              </label>
              <div className="relative">
                <input
                  type="text"
                  required
                  value={formData.dateOfBirth}
                  onChange={(e) => {
                    const formattedValue = formatDobInput(e.target.value)
                    setFormData({...formData, dateOfBirth: formattedValue})
                    // Clear error when user starts typing
                    if (formattedValue.length === 10) {
                      const error = validateDob(formattedValue)
                      setDobError(error)
                    } else {
                      setDobError('')
                    }
                  }}
                  onBlur={(e) => {
                    const error = validateDob(e.target.value)
                    setDobError(error)
                  }}
                  placeholder="DD/MM/YYYY"
                  maxLength={10}
                  className={`w-full px-4 py-2 border rounded-lg focus:ring-2 focus:border-transparent ${
                    dobError 
                      ? 'border-red-300 focus:ring-red-500 focus:border-red-500' 
                      : 'border-gray-300 focus:ring-blue-500 focus:border-blue-500'
                  }`}
                />
                <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                  <Calendar className="h-5 w-5 text-gray-400" />
                </div>
              </div>
               
            </div>
            
            {/* Address */}
            <div className="lg:col-span-1 xl:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Address *
              </label>
              <textarea
                required
                value={formData.address}
                onChange={(e) => setFormData({...formData, address: e.target.value})}
                rows={3}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter complete address"
              />
            </div>
            
            {/* Pincode */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Pincode *
              </label>
              <input
                type="text"
                required
                value={formData.pincode}
                onChange={(e) => setFormData({...formData, pincode: e.target.value})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter pincode"
                maxLength={6}
              />
            </div>
            
            {/* Cell Number */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Cell Number *
              </label>
              <input
                type="tel"
                required
                value={formData.cellNo}
                onChange={(e) => setFormData({...formData, cellNo: e.target.value})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter mobile number"
                maxLength={10}
              />
            </div>
            
            {/* Email */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Email ID
              </label>
              <input
                type="email"
                value={formData.emailId || 'g@gmail.com'}
                onChange={(e) => setFormData({...formData, emailId: e.target.value})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="Enter email address"
              />
            </div>
            
            
            {/* Refer By */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Refer By
              </label>
              <select
                value={formData.refer}
                onChange={(e) => setFormData({...formData, refer: e.target.value})}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="">Select referral source</option>
                <option value="Self">Self</option>
                <option value="VAO's">VAO's</option>
                <option value="Others">Others</option>
                <option value="Exist Customer">Exist Customer</option>
              </select>
              </div>
              {/* Referral Name Field */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Referral Name
                </label>
                <input
                  type="text"
                  value={formData.referName || ''}
                  onChange={(e) => setFormData({...formData, referName: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Enter referral person's name"
                />
              </div>
          </div>
        </div>

        {/* ID Proof Information Section */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
            <span className="w-1 h-6 bg-green-600 mr-3 rounded"></span>
            ID Proof Information
          </h3>
          <div className="flex flex-col lg:flex-row gap-4">
           {/* CAN no*/}
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    E Sevai CAN No.
                  </label>
                  <input
                    type="text"
                    value={formData.otherIdDetails || ''}
                    onChange={(e) => setFormData({...formData, otherIdDetails: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                    placeholder="Other ID"
                  />
                </div>
                {/* Aadhaar Number */}
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Aadhaar Number
                  </label>
                  <input
                    type="text"
                    value={formData.aadhaarNumber || ''}
                    onChange={(e) => setFormData({...formData, aadhaarNumber: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                    placeholder="12-digit"
                    maxLength={12}
                  />
                </div>

                {/* PAN Card Number */}
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    PAN Card Number
                  </label>
                  <input
                    type="text"
                    value={formData.panCardNumber || ''}
                    onChange={(e) => setFormData({...formData, panCardNumber: e.target.value.toUpperCase()})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                    placeholder="10-digit"
                    maxLength={10}
                  />
                </div>

                {/* Ration Card Number */}
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Ration Card Number
                  </label>
                  <input
                    type="text"
                    value={formData.rationCardNumber || ''}
                    onChange={(e) => setFormData({...formData, rationCardNumber: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                    placeholder="Ration card"
                  />
                </div>

                {/* Voter ID Number */}
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Voter ID Number
                  </label>
                  <input
                    type="text"
                    value={formData.voterIdNumber || ''}
                    onChange={(e) => setFormData({...formData, voterIdNumber: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                    placeholder="Voter ID"
                  />
                </div>

               
              </div>
        </div>

        {/* Service Information Section */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
            <span className="w-1 h-6 bg-purple-600 mr-3 rounded"></span>
            Service Information
          </h3>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Service Dropdown */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Service *
              </label>
              <div className="relative z-10">
                <select
                  value={formData.service}
                  onChange={(e) => {
                    console.log('Service dropdown changed:', e.target.value);
                    setFormData({...formData, service: e.target.value, subService: ''})
                    // Fetch sub-services when service changes
                    if (e.target.value) {
                      fetchSubServices(e.target.value)
                    } else {
                      setSubServices([])
                    }
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent cursor-pointer bg-white hover:border-gray-400 transition-colors disabled:bg-gray-100 disabled:cursor-not-allowed"
                  disabled={loading}
                  required
                >
                  <option value="">Select Service</option>
                  {services.map((service) => (
                    <option key={service._id} value={service._id}>
                      {service.serviceName}
                    </option>
                  ))}
                </select>
                <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                  <ChevronDown className="w-4 h-4 text-gray-400" />
                </div>
              </div>
              {loadingServices && (
                <p className="text-xs text-gray-500 mt-1">Loading services...</p>
              )}
              {!loadingServices && services.length === 0 && (
                <p className="text-xs text-gray-500 mt-1">No services available. Please add services in Settings.</p>
              )}
            </div>

            {/* Sub-Service Dropdown */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Sub-Service *
              </label>
              <div className="relative z-10">
                <select
                  value={formData.subService}
                  onChange={(e) => {
                    console.log('Sub-service dropdown changed:', e.target.value);
                    setFormData({...formData, subService: e.target.value})
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent cursor-pointer bg-white hover:border-gray-400 transition-colors disabled:bg-gray-100 disabled:cursor-not-allowed"
                  disabled={loading || !formData.service || loadingSubServices}
                  required
                >
                  <option value="">Select Sub-Service</option>
                  {subServices.map((subService) => (
                    <option key={subService._id} value={subService._id}>
                      {subService.subServiceName}
                    </option>
                  ))}
                </select>
                <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                  <ChevronDown className="w-4 h-4 text-gray-400" />
                </div>
              </div>
              {loadingSubServices && (
                <p className="text-xs text-gray-500 mt-1">Loading sub-services...</p>
              )}
              {!formData.service && !loadingSubServices && (
                <p className="text-xs text-gray-500 mt-1">Please select a service first</p>
              )}
              {formData.service && !loadingSubServices && subServices.length === 0 && (
                <p className="text-xs text-gray-500 mt-1">No sub-services available for this service</p>
              )}
            </div>

            {/* Staff Dropdown */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Assigned Staff *
              </label>
              <div className="relative z-10">
                <select
                  value={formData.staff}
                  onChange={(e) => {
                    console.log('Staff dropdown changed:', e.target.value);
                    setFormData({...formData, staff: e.target.value})
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent cursor-pointer bg-white hover:border-gray-400 transition-colors disabled:bg-gray-100 disabled:cursor-not-allowed"
                  disabled={loading || loadingStaff}
                  required
                >
                  <option value="">Select Staff</option>
                  {staff.map((staffMember) => (
                    <option key={staffMember._id} value={staffMember._id}>
                      {staffMember.name} - {staffMember.role}
                    </option>
                  ))}
                </select>
                <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                  <ChevronDown className="w-4 h-4 text-gray-400" />
                </div>
              </div>
              {loadingStaff && (
                <p className="text-xs text-gray-500 mt-1">Loading staff...</p>
              )}
              {!loadingStaff && staff.length === 0 && (
                <p className="text-xs text-gray-500 mt-1">No staff available. Please add staff in Settings.</p>
              )}
            </div>
                </div>

                {/* Customer Photo */}
                <div className="lg:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Customer Photo
              </label>
              <div className="flex items-center space-x-4">
                <div className="relative">
                  {photoPreview || (editingCustomer && editingCustomer.photo) ? (
                    <div className="relative">
                      <img 
                        src={photoPreview || getImageUrl(editingCustomer?.photo)}
                        alt="Customer" 
                        className="h-20 w-20 rounded-full object-cover border-2 border-gray-200"
                        onError={handleImageError}
                      />
                      {/* Fallback placeholder */}
                      <div 
                        className="h-20 w-20 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300 absolute top-0 left-0"
                        style={{ display: 'none' }}
                      >
                        <UserPlus className="h-10 w-10 text-gray-400" />
                      </div>
                      {editingCustomer?.photo && !photoPreview && (
                        <button
                          onClick={handlePhotoDelete}
                          className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-1 hover:bg-red-600 transition-colors"
                          title="Delete photo"
                        >
                          <X className="h-3 w-3" />
                        </button>
                      )}
                    </div>
                  ) : (
                    <div className="h-20 w-20 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                      <UserPlus className="h-10 w-10 text-gray-400" />
                    </div>
                  )}
                </div>
                
                <div className="flex-1">
                  <input
                    type="file"
                    id="photo-upload"
                    accept="image/*"
                    onChange={handlePhotoChange}
                    className="hidden"
                  />
                  <label
                    htmlFor="photo-upload"
                    className="inline-flex items-center px-3 py-1 border border-gray-300 rounded shadow-sm text-xs font-medium text-gray-700 bg-white hover:bg-gray-50 cursor-pointer transition-colors"
                  >
                    <Camera className="h-4 w-4 mr-1" />
                    Choose Photo
                  </label>
                  
                  {selectedPhoto && (
                    <div className="mt-2">
                      <p className="text-xs text-gray-600">
                        Selected: {selectedPhoto.name}
                      </p>
                      <div className="flex items-center space-x-2 mt-1">
                        <button
                          type="button"
                          onClick={() => {
                            setSelectedPhoto(null)
                            setPhotoPreview(null)
                          }}
                          className="px-2 py-1 text-xs bg-gray-200 text-gray-700 rounded hover:bg-gray-300 transition-colors"
                        >
                          Remove
                        </button>
                      </div>
                    </div>
                  )}
                </div>
          </div>
        </div>
</div>
        {/* Action Buttons Section */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 mt-6">
          <div className="flex justify-end space-x-4">
            <button
              type="button"
              onClick={() => {
                if (window.confirm('Are you sure you want to discard your changes?')) {
                  resetForm()
                  window.history.pushState({}, '', '/customer-management?tab=customers')
                  window.dispatchEvent(new PopStateEvent('popstate'))
                }
              }}
              className="px-6 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center"
            >
              {loading ? (
                <>
                  <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white mr-2"></div>
                  Saving...
                </>
              ) : (
                <>
                  <Save className="h-5 w-5 mr-2" />
                  {editingCustomer ? 'Update Customer' : 'Add Customer'}
                </>
              )}
            </button>
          </div>
        </div>

      </form>

      {/* Custom Confirmation Dialog */}
      {showConfirmDialog && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl p-6 max-w-md w-full mx-4 transform transition-all">
            <div className="flex items-center mb-4">
              <AlertCircle className="h-7 w-7 text-amber-500 mr-3" />
              <h3 className="text-lg font-semibold text-gray-900">Confirm Save</h3>
            </div>
            
            <div className="mb-6">
              <p className="text-gray-700 mb-3">
                Are you sure you want to save this customer?
              </p>
              {formData.emailId && formData.emailId !== 'g@gmail.com' && (
                <div className="bg-amber-50 border border-amber-200 rounded-lg p-3">
                  <p className="text-sm text-amber-800">
                    <strong>Email:</strong> {formData.emailId}
                  </p>
                  <p className="text-xs text-amber-600 mt-1">
                    The email will be saved as entered.
                  </p>
                </div>
              )}
            </div>
            
            <div className="flex justify-end space-x-3">
              <button
                onClick={() => {
                  setShowConfirmDialog(false)
                  setPendingSubmit(null)
                }}
                className="px-4 py-2 text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={async () => {
                  setShowConfirmDialog(false)
                  if (pendingSubmit) {
                    await pendingSubmit()
                    setPendingSubmit(null)
                  }
                }}
                className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg transition-colors flex items-center"
              >
                <Save className="h-4 w-4 mr-2" />
                Save Customer
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default CustomerAdd
