import React, { useState, useEffect } from 'react'
import { useSearchParams, useNavigate } from 'react-router-dom'
import AssignedStaff from './AssignedStaff'
import SiteBackup from './SiteBackup'
import UserManagement from './UserManagement'
import Security from './Security'
import PinVerification from '../../components/PinVerification'
import { Settings as SettingsIcon, TrendingUp, Users, Archive, Shield, Lock, CheckCircle } from 'lucide-react'
import { useAdminAuth } from '../../hooks/useAdminAuth'

const Settings = () => {
  const [searchParams] = useSearchParams()
  const navigate = useNavigate()
  const activeTab = searchParams.get('tab') || 'assigned-staff'
  const { isAdmin, canAccess, isLoading } = useAdminAuth()
  const [showPinVerification, setShowPinVerification] = useState(false)
  const [isPinVerified, setIsPinVerified] = useState(false)
  const [pinRequired, setPinRequired] = useState(false)

  const allTabs = [
    { 
      id: 'assigned-staff', 
      name: 'Assigned Staff', 
      icon: Users, 
      component: AssignedStaff,
      color: 'blue',
      permission: 'settings'
    },
    { 
      id: 'site-backup', 
      name: 'Site Backup', 
      icon: Archive, 
      component: SiteBackup,
      color: 'indigo',
      permission: 'settings'
    },
    { 
      id: 'security', 
      name: 'Security', 
      icon: Lock, 
      component: Security,
      color: 'purple',
      permission: 'settings'
    },
    { 
      id: 'user-management', 
      name: 'User Management', 
      icon: Shield, 
      component: UserManagement,
      color: 'cyan',
      permission: 'settings',
      adminOnly: true
    }
  ]

  // Filter tabs based on user permissions
  const tabs = allTabs.filter(tab => {
    if (tab.adminOnly && !isAdmin) return false
    if (tab.permission && !canAccess(tab.permission)) return false
    return true
  })

  // Check if PIN is required and verified
  useEffect(() => {
    const checkPinRequirement = () => {
      const storedPin = localStorage.getItem('appSecurityPin')
      
      // Check if PIN exists and verification is needed
      if (storedPin) {
        setPinRequired(true)
        // Always show PIN verification when settings page loads
        setShowPinVerification(true)
        setIsPinVerified(false)
      } else {
        setPinRequired(false)
        setIsPinVerified(true)
      }
    }
    
    checkPinRequirement()
  }, [])

  // Handle PIN verification success
  const handlePinVerified = () => {
    setIsPinVerified(true)
    setShowPinVerification(false)
    // Don't store verification - require PIN every time
  }

  // Handle PIN verification cancel
  const handlePinCancel = () => {
    // Navigate back to previous page or dashboard
    window.history.back()
  }

  // Find active component or fallback to first available tab
  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || tabs[0]?.component || AssignedStaff

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  if (!isAdmin && tabs.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <Shield className="h-12 w-4 text-gray-400 mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Access Denied</h2>
          <p className="text-gray-600">You don't have permission to access settings.</p>
        </div>
      </div>
    )
  }

  return (
    <>
      {/* PIN Verification Modal */}
      {showPinVerification && (
        <PinVerification
          onVerified={handlePinVerified}
          onCancel={handlePinCancel}
          title="Enter PIN to Access Settings"
        />
      )}
      
      {/* Settings Page */}
      {isPinVerified && (
        <div className="h-screen overflow-y-auto bg-gray-50">
          {/* Header */}
                  {/* Tabs */}
          <div className="bg-white border-b border-gray-200">
            <div className="px-4 lg:px-8">
              <nav className="flex space-x-8 overflow-x-auto">
                {tabs.map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => {
                      // Navigate to tab without clearing PIN verification
                      navigate(`/settings?tab=${tab.id}`)
                    }}
                    className={`py-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${
                      activeTab === tab.id
                        ? `border-${tab.color}-500 text-${tab.color}-600`
                        : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <div className="flex items-center space-x-2">
                      <tab.icon className="h-4 w-4" />
                      <span>{tab.name}</span>
                    </div>
                  </button>
                ))}
              </nav>
            </div>
          </div>

          {/* Content */}
          <div className="px-4 lg:px-8 py-6">
            <ActiveComponent />
          </div>
        </div>
      )}
    </>
  )
}

export default Settings
