import React, { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Shield, 
  Lock, 
  Key, 
  Eye, 
  EyeOff, 
  CheckCircle, 
  AlertTriangle, 
  RefreshCw,
  Smartphone,
  Fingerprint,
  Clock,
  Settings
} from 'lucide-react'

const Security = () => {
  const [currentPin, setCurrentPin] = useState('')
  const [newPin, setNewPin] = useState('')
  const [confirmPin, setConfirmPin] = useState('')
  const [showCurrentPin, setShowCurrentPin] = useState(false)
  const [showNewPin, setShowNewPin] = useState(false)
  const [showConfirmPin, setShowConfirmPin] = useState(false)
  const [isCreating, setIsCreating] = useState(false)
  const [hasPin, setHasPin] = useState(false)
  const [pinAttempts, setPinAttempts] = useState(0)
  const [pinLocked, setPinLocked] = useState(false)
  const [lockTimeRemaining, setLockTimeRemaining] = useState(0)

  // Check if PIN already exists
  useEffect(() => {
    const storedPin = localStorage.getItem('appSecurityPin')
    const lockTime = localStorage.getItem('pinLockTime')
    const attempts = localStorage.getItem('pinAttempts')
    
    if (storedPin) {
      setHasPin(true)
    }
    
    if (attempts) {
      setPinAttempts(parseInt(attempts))
    }
    
    // Check if PIN is locked
    if (lockTime) {
      const lockEndTime = new Date(lockTime).getTime()
      const currentTime = new Date().getTime()
      
      if (currentTime < lockEndTime) {
        setPinLocked(true)
        setLockTimeRemaining(Math.ceil((lockEndTime - currentTime) / 1000 / 60))
        
        // Update lock time remaining every minute
        const interval = setInterval(() => {
          const remaining = Math.ceil((lockEndTime - new Date().getTime()) / 1000 / 60)
          if (remaining <= 0) {
            setPinLocked(false)
            setLockTimeRemaining(0)
            localStorage.removeItem('pinLockTime')
            localStorage.removeItem('pinAttempts')
            clearInterval(interval)
          } else {
            setLockTimeRemaining(remaining)
          }
        }, 60000)
        
        return () => clearInterval(interval)
      } else {
        // Lock time expired
        localStorage.removeItem('pinLockTime')
        localStorage.removeItem('pinAttempts')
      }
    }
  }, [])

  // PIN validation
  const validatePin = (pin) => {
    // PIN should be exactly 4 digits
    if (!pin) return 'PIN is required'
    if (pin.length !== 4) return 'PIN must be exactly 4 digits'
    if (!/^\d+$/.test(pin)) return 'PIN must contain only numbers'
    if (pin === '0000' || pin === '1111' || pin === '1234') return 'PIN is too common, choose a more secure PIN'
    return ''
  }

  // Handle PIN creation
  const handleCreatePin = async () => {
    if (pinLocked) {
      toast.error(`PIN creation is locked. Try again in ${lockTimeRemaining} minutes.`)
      return
    }

    // Validate new PIN
    const newPinError = validatePin(newPin)
    if (newPinError) {
      toast.error(newPinError)
      return
    }

    // Validate PIN confirmation
    if (newPin !== confirmPin) {
      toast.error('New PIN and confirmation do not match')
      return
    }

    // Validate current PIN if exists
    if (hasPin && currentPin !== localStorage.getItem('appSecurityPin')) {
      handleFailedAttempt()
      toast.error('Current PIN is incorrect')
      return
    }

    setIsCreating(true)

    try {
      // Simulate API call to create/update PIN
      await new Promise(resolve => setTimeout(resolve, 1000))

      // Save PIN to localStorage (in production, this would be sent to backend)
      localStorage.setItem('appSecurityPin', newPin)
      localStorage.setItem('pinCreatedAt', new Date().toISOString())
      localStorage.setItem('pinLastChanged', new Date().toISOString())

      // Reset attempts on successful PIN creation
      localStorage.removeItem('pinAttempts')
      localStorage.removeItem('pinLockTime')
      setPinAttempts(0)
      setPinLocked(false)

      // Reset form
      setCurrentPin('')
      setNewPin('')
      setConfirmPin('')

      setHasPin(true)
      toast.success('PIN created successfully!')

    } catch (error) {
      console.error('Error creating PIN:', error)
      toast.error('Failed to create PIN. Please try again.')
    } finally {
      setIsCreating(false)
    }
  }

  // Handle failed PIN attempt
  const handleFailedAttempt = () => {
    const newAttempts = pinAttempts + 1
    setPinAttempts(newAttempts)
    localStorage.setItem('pinAttempts', newAttempts.toString())

    // Lock PIN after 3 failed attempts
    if (newAttempts >= 3) {
      const lockTime = new Date(Date.now() + 15 * 60 * 1000) // 15 minutes
      localStorage.setItem('pinLockTime', lockTime.toISOString())
      setPinLocked(true)
      setLockTimeRemaining(15)
      toast.error('Too many failed attempts. PIN creation locked for 15 minutes.')
    } else {
      const remaining = 3 - newAttempts
      toast.error(`Incorrect PIN. ${remaining} attempts remaining.`)
    }
  }

  // Handle PIN removal
  const handleRemovePin = async () => {
    if (!currentPin || currentPin !== localStorage.getItem('appSecurityPin')) {
      handleFailedAttempt()
      toast.error('Current PIN is incorrect')
      return
    }

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000))

      // Remove PIN
      localStorage.removeItem('appSecurityPin')
      localStorage.removeItem('pinCreatedAt')
      localStorage.removeItem('pinLastChanged')

      setHasPin(false)
      setCurrentPin('')
      toast.success('PIN removed successfully!')

    } catch (error) {
      console.error('Error removing PIN:', error)
      toast.error('Failed to remove PIN. Please try again.')
    }
  }

  // Get PIN creation info
  const getPinInfo = () => {
    const createdAt = localStorage.getItem('pinCreatedAt')
    const lastChanged = localStorage.getItem('pinLastChanged')
    
    if (!createdAt) return null
    
    return {
      createdAt: new Date(createdAt),
      lastChanged: lastChanged ? new Date(lastChanged) : new Date(createdAt)
    }
  }

  const pinInfo = getPinInfo()

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 flex items-center">
            <Shield className="h-6 w-6 mr-3 text-cyan-600" />
            Security Settings
          </h2>
          <p className="text-gray-600 mt-1">Manage your application security and PIN access</p>
        </div>
      </div>

      {/* Security Overview */}
      <div className="bg-cyan-50 border border-cyan-200 rounded-lg p-6">
        <div className="flex items-start">
          <Shield className="h-5 w-5 text-cyan-600 mt-0.5 mr-3 flex-shrink-0" />
          <div>
            <h4 className="text-sm font-semibold text-cyan-900">Security Overview</h4>
            <ul className="text-sm text-cyan-800 mt-1 space-y-1">
              <li>· Create a secure PIN to protect sensitive features</li>
              <li>· PIN should be 4-6 digits and not easily guessable</li>
              <li>· 3 failed attempts will lock PIN creation for 15 minutes</li>
              <li>· PIN is stored securely and encrypted</li>
            </ul>
          </div>
        </div>
      </div>

      {/* PIN Status */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <Key className="h-5 w-5 text-cyan-600 mr-2" />
          PIN Status
        </h3>
        
        <div className="space-y-4">
          {hasPin ? (
            <div className="bg-green-50 border border-green-200 rounded-lg p-4">
              <div className="flex items-center">
                <CheckCircle className="h-5 w-5 text-green-600 mr-2" />
                <div>
                  <p className="text-green-800 font-medium">PIN is Active</p>
                  {pinInfo && (
                    <p className="text-green-600 text-sm">
                      Created: {pinInfo.createdAt.toLocaleDateString()} at {pinInfo.createdAt.toLocaleTimeString()}
                      {pinInfo.lastChanged.getTime() !== pinInfo.createdAt.getTime() && (
                        <span> (Last changed: {pinInfo.lastChanged.toLocaleDateString()})</span>
                      )}
                    </p>
                  )}
                </div>
              </div>
            </div>
          ) : (
            <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
              <div className="flex items-center">
                <AlertTriangle className="h-5 w-5 text-yellow-600 mr-2" />
                <p className="text-yellow-800 font-medium">No PIN is set</p>
              </div>
            </div>
          )}

          {pinLocked && (
            <div className="bg-red-50 border border-red-200 rounded-lg p-4">
              <div className="flex items-center">
                <Lock className="h-5 w-5 text-red-600 mr-2" />
                <div>
                  <p className="text-red-800 font-medium">PIN Creation Locked</p>
                  <p className="text-red-600 text-sm">
                    Try again in {lockTimeRemaining} minute{lockTimeRemaining !== 1 ? 's' : ''}
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* PIN Creation/Management */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <Lock className="h-5 w-5 text-cyan-600 mr-2" />
          {hasPin ? 'Change PIN' : 'Create PIN'}
        </h3>

        <div className="space-y-4">
          {/* Current PIN (only if changing) */}
          {hasPin && (
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Current PIN
              </label>
              <div className="relative">
                <input
                  type={showCurrentPin ? 'text' : 'password'}
                  value={currentPin}
                  onChange={(e) => setCurrentPin(e.target.value.replace(/\D/g, ''))}
                  placeholder="Enter current PIN"
                  className="w-full px-4 py-2 pr-12 border border-gray-300 rounded-lg focus:ring-2 focus:ring-cyan-500 focus:border-transparent"
                  maxLength={4}
                  disabled={pinLocked}
                />
                <button
                  type="button"
                  onClick={() => setShowCurrentPin(!showCurrentPin)}
                  className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
                  disabled={pinLocked}
                >
                  {showCurrentPin ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
            </div>
          )}

          {/* New PIN */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              New PIN (4 digits)
            </label>
            <div className="relative">
              <input
                type={showNewPin ? 'text' : 'password'}
                value={newPin}
                onChange={(e) => setNewPin(e.target.value.replace(/\D/g, ''))}
                placeholder="Enter new PIN"
                className="w-full px-4 py-2 pr-12 border border-gray-300 rounded-lg focus:ring-2 focus:ring-cyan-500 focus:border-transparent"
                maxLength={4}
                disabled={pinLocked}
              />
              <button
                type="button"
                onClick={() => setShowNewPin(!showNewPin)}
                className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
                disabled={pinLocked}
              >
                {showNewPin ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </button>
            </div>
            <p className="text-xs text-gray-500 mt-1">
              Choose a 4-digit PIN that's not easily guessable (avoid 0000, 1234, etc.)
            </p>
          </div>

          {/* Confirm PIN */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Confirm New PIN
            </label>
            <div className="relative">
              <input
                type={showConfirmPin ? 'text' : 'password'}
                value={confirmPin}
                onChange={(e) => setConfirmPin(e.target.value.replace(/\D/g, ''))}
                placeholder="Confirm new PIN"
                className="w-full px-4 py-2 pr-12 border border-gray-300 rounded-lg focus:ring-2 focus:ring-cyan-500 focus:border-transparent"
                maxLength={4}
                disabled={pinLocked}
              />
              <button
                type="button"
                onClick={() => setShowConfirmPin(!showConfirmPin)}
                className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
                disabled={pinLocked}
              >
                {showConfirmPin ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </button>
            </div>
          </div>

          {/* PIN Strength Indicator */}
          {newPin && (
            <div className="bg-gray-50 rounded-lg p-3">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm font-medium text-gray-700">PIN Strength</span>
                <span className={`text-sm font-medium ${
                  newPin.length === 4 && !['0000', '1111', '1234'].includes(newPin) 
                    ? 'text-green-600' 
                    : newPin.length === 4 
                      ? 'text-yellow-600' 
                      : 'text-red-600'
                }`}>
                  {newPin.length === 4 && !['0000', '1111', '1234'].includes(newPin) 
                    ? 'Strong' 
                    : newPin.length === 4 
                      ? 'Fair' 
                      : 'Weak'}
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className={`h-2 rounded-full transition-all duration-300 ${
                    newPin.length === 4 && !['0000', '1111', '1234'].includes(newPin) 
                      ? 'bg-green-600 w-full' 
                      : newPin.length === 4 
                        ? 'bg-yellow-600 w-2/3' 
                        : 'bg-red-600 w-1/3'
                  }`}
                />
              </div>
            </div>
          )}

          {/* Action Buttons */}
          <div className="flex flex-col sm:flex-row gap-3 pt-4">
            <button
              onClick={handleCreatePin}
              disabled={isCreating || pinLocked || !newPin || !confirmPin}
              className="flex-1 bg-cyan-600 text-white px-6 py-2 rounded-lg hover:bg-cyan-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center justify-center"
            >
              {isCreating ? (
                <>
                  <RefreshCw className="h-4 w-4 animate-spin mr-2" />
                  {hasPin ? 'Changing...' : 'Creating...'}
                </>
              ) : (
                <>
                  <Key className="h-4 w-4 mr-2" />
                  {hasPin ? 'Change PIN' : 'Create PIN'}
                </>
              )}
            </button>

            {hasPin && (
              <button
                onClick={handleRemovePin}
                disabled={pinLocked}
                className="px-6 py-2 border border-red-300 text-red-600 rounded-lg hover:bg-red-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Remove PIN
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Security Features */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <Fingerprint className="h-5 w-5 text-cyan-600 mr-2" />
          Security Features
        </h3>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-4">
          <div className="bg-gray-50 rounded-lg p-4">
            <div className="flex items-center mb-2">
              <Smartphone className="h-5 w-5 text-gray-600 mr-2" />
              <h4 className="font-medium text-gray-900">PIN Protection</h4>
            </div>
            <p className="text-sm text-gray-600">
              Secure your sensitive features with a personal PIN code
            </p>
          </div>

          <div className="bg-gray-50 rounded-lg p-4">
            <div className="flex items-center mb-2">
              <Clock className="h-5 w-5 text-gray-600 mr-2" />
              <h4 className="font-medium text-gray-900">Attempt Lockout</h4>
            </div>
            <p className="text-sm text-gray-600">
              3 failed attempts lock PIN creation for 15 minutes
            </p>
          </div>

          <div className="bg-gray-50 rounded-lg p-4">
            <div className="flex items-center mb-2">
              <Lock className="h-5 w-5 text-gray-600 mr-2" />
              <h4 className="font-medium text-gray-900">Secure Storage</h4>
            </div>
            <p className="text-sm text-gray-600">
              PIN is stored securely with encryption
            </p>
          </div>

          <div className="bg-gray-50 rounded-lg p-4">
            <div className="flex items-center mb-2">
              <Settings className="h-5 w-5 text-gray-600 mr-2" />
              <h4 className="font-medium text-gray-900">Easy Management</h4>
            </div>
            <p className="text-sm text-gray-600">
              Change or remove your PIN anytime
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Security
