import React, { useState, useEffect } from 'react'
import { Calendar, TrendingUp, TrendingDown, DollarSign, Filter, Download, Search, RefreshCw, ArrowUpRight, ArrowDownRight, Users, Receipt, CreditCard, Banknote, FileText } from 'lucide-react'
import { billsAPI } from '../services/api'
import { expenseAPI } from '../services/settingsAPI'
import { formatCurrency } from '../utils/currencyUtils'
import { toast } from 'react-hot-toast'

const IncomeExpense = () => {
  const [activeTab, setActiveTab] = useState('income')
  const [bills, setBills] = useState([])
  const [expenses, setExpenses] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterDate, setFilterDate] = useState('')
  const [filterMonth, setFilterMonth] = useState('')
  const [filterYear, setFilterYear] = useState(new Date().getFullYear().toString())
  const [searchTerm, setSearchTerm] = useState('')
  const [filterPaymentMethod, setFilterPaymentMethod] = useState('all')
  const [filterCategory, setFilterCategory] = useState('all')

  // Summary calculations
  const [summary, setSummary] = useState({
    totalIncome: 0,
    totalExpense: 0,
    profit: 0,
    profitMargin: 0,
    totalTransactions: 0,
    averageTransaction: 0,
    todayIncome: 0,
    todayExpense: 0,
    todayProfit: 0,
    todayCashIncome: 0,
    todayUPIIncome: 0,
    todayCreditCardIncome: 0,
    todayBankTransferIncome: 0,
    thisMonthIncome: 0,
    thisMonthExpense: 0,
    thisMonthProfit: 0,
    thisYearIncome: 0,
    thisYearExpense: 0,
    thisYearProfit: 0
  })

  useEffect(() => {
    fetchFinancialData()
  }, [filterMonth, filterYear, filterDate, searchTerm, filterPaymentMethod, filterCategory, activeTab])

  // Listen for expense data changes from other components
  useEffect(() => {
    const handleExpenseDataChanged = (e) => {
      console.log('Expense data changed event received in IncomeExpense:', e.detail)
      fetchFinancialData()
    }

    // Listen for storage changes (for localStorage updates)
    const handleStorageChange = (e) => {
      if (e.key === 'expenses') {
        console.log('Expenses storage changed in IncomeExpense')
        fetchFinancialData()
      }
    }

    // Listen for custom expense data changes
    window.addEventListener('expenseDataChanged', handleExpenseDataChanged)
    
    // Listen for storage changes
    window.addEventListener('storage', handleStorageChange)
    
    // Cleanup listeners on unmount
    return () => {
      window.removeEventListener('expenseDataChanged', handleExpenseDataChanged)
      window.removeEventListener('storage', handleStorageChange)
    }
  }, [])

  // Refresh data when page becomes visible again (navigation back to page)
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (!document.hidden) {
        console.log('Page became visible, refreshing IncomeExpense data')
        fetchFinancialData()
      }
    }

    // Listen for visibility changes
    document.addEventListener('visibilitychange', handleVisibilityChange)
    
    // Cleanup listener on unmount
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange)
    }
  }, [])

  // Listen for expense data changes from other components to refresh Today's Summary
  useEffect(() => {
    const handleExpenseDataChanged = (e) => {
      console.log('Expense data changed event received in IncomeExpense Today\'s Summary:', e.detail)
      fetchFinancialData()
    }

    // Listen for custom expense data changes
    window.addEventListener('expenseDataChanged', handleExpenseDataChanged)
    
    // Cleanup listener on unmount
    return () => {
      window.removeEventListener('expenseDataChanged', handleExpenseDataChanged)
    }
  }, [])

  const fetchFinancialData = async () => {
    try {
      setLoading(true)
      
      // Fetch bills data
      const billsResponse = await billsAPI.getAll()
      const allBills = billsResponse.data || []
      
      // Fetch expenses data from API first
      let allExpenses = []
      try {
        const expensesResponse = await expenseAPI.getExpenses()
        allExpenses = expensesResponse || []
        console.log('Expenses loaded from API in IncomeExpense:', allExpenses)
      } catch (apiError) {
        console.log('API not available, trying localStorage for expenses')
        // Fallback to localStorage if API fails
        try {
          const savedExpenses = localStorage.getItem('expenses')
          if (savedExpenses) {
            allExpenses = JSON.parse(savedExpenses)
          }
        } catch (localStorageError) {
          console.error('Error loading expenses from localStorage:', localStorageError)
          allExpenses = []
        }
      }
      
      // Apply filters
      const filteredBills = filterData(allBills, 'income')
      const filteredExpenses = filterData(allExpenses, 'expense')
      
      setBills(filteredBills)
      setExpenses(filteredExpenses)
      
      // Calculate summary
      calculateSummary(filteredBills, filteredExpenses)
    } catch (error) {
      console.error('Error fetching financial data:', error)
      toast.error('Failed to load financial data')
    } finally {
      setLoading(false)
    }
  }

  const filterData = (data, type) => {
    return data.filter(item => {
      const itemDate = new Date(item.billDate || item.date || item.createdAt)
      
      // Year filter
      if (filterYear && itemDate.getFullYear().toString() !== filterYear) {
        return false
      }
      
      // Month filter
      if (filterMonth) {
        const itemMonth = (itemDate.getMonth() + 1).toString().padStart(2, '0')
        if (itemMonth !== filterMonth) {
          return false
        }
      }
      
      // Date filter
      if (filterDate) {
        const itemDateStr = itemDate.toISOString().split('T')[0]
        if (itemDateStr !== filterDate) {
          return false
        }
      }
      
      // Search filter
      if (searchTerm) {
        const searchLower = searchTerm.toLowerCase()
        const matchesSearch = 
          (item.customerName && item.customerName.toLowerCase().includes(searchLower)) ||
          (item.billNo && item.billNo.toLowerCase().includes(searchLower)) ||
          (item.description && item.description.toLowerCase().includes(searchLower)) ||
          (item.category && item.category.toLowerCase().includes(searchLower)) ||
          (item.name && item.name.toLowerCase().includes(searchLower))
        
        if (!matchesSearch) {
          return false
        }
      }
      
      // Payment method filter (for income)
      if (type === 'income' && filterPaymentMethod !== 'all') {
        if (item.paymentMethod !== filterPaymentMethod) {
          return false
        }
      }
      
      // Category filter (for expenses)
      if (type === 'expense' && filterCategory !== 'all') {
        if (item.category !== filterCategory) {
          return false
        }
      }
      
      return true
    })
  }

  const calculateSummary = (incomeData, expenseData) => {
    const totalIncome = incomeData.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    const totalExpense = expenseData.reduce((sum, expense) => sum + (expense.amount || 0), 0)
    const profit = totalIncome - totalExpense
    const profitMargin = totalIncome > 0 ? (profit / totalIncome) * 100 : 0
    const totalTransactions = incomeData.length + expenseData.length
    const averageTransaction = totalTransactions > 0 ? (totalIncome + totalExpense) / totalTransactions : 0

    // Calculate today's income and expense for Current Summary
    const today = new Date()
    const todayStr = today.toISOString().split('T')[0]
    
    const todayIncomeData = incomeData.filter(bill => new Date(bill.billDate || bill.createdAt).toISOString().split('T')[0] === todayStr)
    const todayIncome = todayIncomeData.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayExpense = expenseData
      .filter(expense => new Date(expense.date || expense.createdAt).toISOString().split('T')[0] === todayStr)
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const todayProfit = todayIncome - todayExpense
    
    // Calculate today's income by payment method
    const todayCashIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'cash')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayUPIIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'upi')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayCreditCardIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'credit_card')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayBankTransferIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'bank_transfer')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)

    // Get current date for monthly calculations
    const currentMonth = today.getMonth()
    const currentYear = today.getFullYear()

    // Calculate cumulative income up to current month
    const thisMonthIncome = incomeData
      .filter(bill => {
        const billDate = new Date(bill.billDate || bill.createdAt)
        return billDate.getFullYear() === currentYear && billDate.getMonth() <= currentMonth
      })
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    // Calculate cumulative expenses up to current month
    const thisMonthExpense = expenseData
      .filter(expense => {
        const expenseDate = new Date(expense.date || expense.createdAt)
        return expenseDate.getFullYear() === currentYear && expenseDate.getMonth() <= currentMonth
      })
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const thisMonthProfit = thisMonthIncome - thisMonthExpense

    // Calculate monthly income by payment method (cumulative up to current month)
    const thisMonthIncomeData = incomeData.filter(bill => {
      const billDate = new Date(bill.billDate || bill.createdAt)
      return billDate.getFullYear() === currentYear && billDate.getMonth() <= currentMonth
    })
    
    const thisMonthCashIncome = thisMonthIncomeData
      .filter(bill => bill.paymentMethod === 'cash')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisMonthUPIIncome = thisMonthIncomeData
      .filter(bill => bill.paymentMethod === 'upi')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisMonthCreditCardIncome = thisMonthIncomeData
      .filter(bill => bill.paymentMethod === 'credit_card')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisMonthBankTransferIncome = thisMonthIncomeData
      .filter(bill => bill.paymentMethod === 'bank_transfer')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)

    // Calculate this year's income and expense
    const thisYearIncome = incomeData
      .filter(bill => new Date(bill.billDate || bill.createdAt).getFullYear() === currentYear)
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisYearExpense = expenseData
      .filter(expense => new Date(expense.date || expense.createdAt).getFullYear() === currentYear)
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const thisYearProfit = thisYearIncome - thisYearExpense

    // Enhanced debug logging for Today's Summary comparison
    console.log('=== INCOMEEXPENSE TODAY\'S SUMMARY DEBUG ===')
    console.log('Today Income:', todayIncome)
    console.log('Today Expenses:', todayExpense)
    console.log('Today Profit:', todayProfit)
    console.log('Today Cash Income:', todayCashIncome)
    console.log('Today UPI Income:', todayUPIIncome)
    console.log('Today Credit Card Income:', todayCreditCardIncome)
    console.log('Today Bank Transfer Income:', todayBankTransferIncome)
    console.log('=======================================')

    setSummary({
      totalIncome,
      totalExpense,
      profit,
      profitMargin,
      totalTransactions,
      averageTransaction,
      todayIncome,
      todayExpense,
      todayProfit,
      todayCashIncome,
      todayUPIIncome,
      todayCreditCardIncome,
      todayBankTransferIncome,
      thisMonthIncome,
      thisMonthExpense,
      thisMonthProfit,
      thisMonthCashIncome,
      thisMonthUPIIncome,
      thisMonthCreditCardIncome,
      thisMonthBankTransferIncome,
      thisYearIncome,
      thisYearExpense,
      thisYearProfit
    })
  }

  const clearFilters = () => {
    setFilterDate('')
    setFilterMonth('')
    setFilterYear(new Date().getFullYear().toString())
    setSearchTerm('')
    setFilterPaymentMethod('all')
    setFilterCategory('all')
  }

  const exportData = () => {
    const data = activeTab === 'income' ? bills : expenses
    const csvContent = generateCSV(data, activeTab)
    downloadCSV(csvContent, `${activeTab}-report.csv`)
  }

  const generateCSV = (data, type) => {
    if (type === 'income') {
      const headers = ['Bill No', 'Date', 'Customer', 'Amount', 'Payment Method', 'Status']
      const rows = data.map(bill => [
        bill.billNo || '',
        new Date(bill.billDate || bill.createdAt).toLocaleDateString(),
        bill.customerName || '',
        bill.grandTotal || 0,
        bill.paymentMethod || '',
        bill.status || 'pending'
      ])
      return [headers, ...rows].map(row => row.join(',')).join('\n')
    } else {
      const headers = ['Date', 'Category', 'Description', 'Amount', 'Payment Method']
      const rows = data.map(expense => [
        new Date(expense.date || expense.createdAt).toLocaleDateString(),
        expense.category || '',
        expense.description || expense.name || '',
        expense.amount || 0,
        expense.paymentMethod || ''
      ])
      return [headers, ...rows].map(row => row.join(',')).join('\n')
    }
  }

  const downloadCSV = (content, filename) => {
    const blob = new Blob([content], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    window.URL.revokeObjectURL(url)
  }

  const getUniqueCategories = () => {
    const categories = [...new Set(expenses.map(exp => exp.category || exp.expenseCategory).filter(Boolean))]
    return categories.sort()
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Today's Summary and Monthly Overview in same row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Today's Summary */}
        <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl p-6 border border-indigo-200">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
            <Calendar className="h-5 w-5 text-indigo-600 mr-2" />
            Today's Summary
          </h3>
          
          <div className="space-y-4">
            {/* Main Summary Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-3">
                  <div className="w-8 h-8 bg-green-100 rounded-lg flex items-center justify-center">
                    <TrendingUp className="h-4 w-4 text-green-600" />
                  </div>
                  <span className="text-sm font-medium text-gray-700">Income</span>
                </div>
                <p className="text-lg font-bold text-gray-900">{formatCurrency(summary.todayIncome)}</p>
                <div className="text-xs text-green-600 mt-1">+12.5%</div>
              </div>

              <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-3">
                  <div className="w-8 h-8 bg-red-100 rounded-lg flex items-center justify-center">
                    <TrendingDown className="h-4 w-4 text-red-600" />
                  </div>
                  <span className="text-sm font-medium text-gray-700">Expense</span>
                </div>
                <p className="text-lg font-bold text-gray-900">{formatCurrency(summary.todayExpense)}</p>
                <div className="text-xs text-red-600 mt-1">-8.3%</div>
              </div>

              <div className={`bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow`}>
                <div className="flex items-center gap-2 mb-3">
                  <div className={`w-8 h-8 ${summary.todayProfit >= 0 ? 'bg-blue-100' : 'bg-orange-100'} rounded-lg flex items-center justify-center`}>
                    {summary.todayProfit >= 0 ? 
                      <ArrowUpRight className="h-4 w-4 text-blue-600" /> : 
                      <ArrowDownRight className="h-4 w-4 text-orange-600" />
                    }
                  </div>
                  <span className="text-sm font-medium text-gray-700">Profit</span>
                </div>
                <p className="text-lg font-bold text-gray-900">{formatCurrency(summary.todayProfit)}</p>
                <div className={`text-xs ${summary.todayProfit >= 0 ? 'text-blue-600' : 'text-orange-600'} mt-1`}>
                  {summary.todayProfit >= 0 ? '+15.2%' : '-5.8%'}
                </div>
              </div>
            </div>

            {/* Payment Method Breakdown - Small Style */}
            <div className="border-t border-indigo-200 pt-4">
              <h4 className="text-sm font-semibold text-gray-700 mb-3">Payment Method Breakdown</h4>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 hover:shadow-md transition-shadow">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-6 h-6 bg-green-100 rounded flex items-center justify-center">
                      <Banknote className="h-3 w-3 text-green-600" />
                    </div>
                    <span className="text-xs font-medium text-gray-700">Cash</span>
                  </div>
                  <p className="text-sm font-bold text-gray-900">{formatCurrency(summary.todayCashIncome)}</p>
                  <div className="text-xs text-gray-500 mt-1">45%</div>
                </div>

                <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 hover:shadow-md transition-shadow">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-6 h-6 bg-purple-100 rounded flex items-center justify-center">
                      <CreditCard className="h-3 w-3 text-purple-600" />
                    </div>
                    <span className="text-xs font-medium text-gray-700">UPI</span>
                  </div>
                  <p className="text-sm font-bold text-gray-900">{formatCurrency(summary.todayUPIIncome)}</p>
                  <div className="text-xs text-gray-500 mt-1">30%</div>
                </div>

                <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 hover:shadow-md transition-shadow">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-6 h-6 bg-blue-100 rounded flex items-center justify-center">
                      <CreditCard className="h-3 w-3 text-blue-600" />
                    </div>
                    <span className="text-xs font-medium text-gray-700">Credit Card</span>
                  </div>
                  <p className="text-sm font-bold text-gray-900">{formatCurrency(summary.todayCreditCardIncome)}</p>
                  <div className="text-xs text-gray-500 mt-1">20%</div>
                </div>

                <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 hover:shadow-md transition-shadow">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-6 h-6 bg-orange-100 rounded flex items-center justify-center">
                      <DollarSign className="h-3 w-3 text-orange-600" />
                    </div>
                    <span className="text-xs font-medium text-gray-700">Bank Transfer</span>
                  </div>
                  <p className="text-sm font-bold text-gray-900">{formatCurrency(summary.todayBankTransferIncome)}</p>
                  <div className="text-xs text-gray-500 mt-1">5%</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Monthly Overview */}
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl p-6 border border-blue-200">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-semibold text-gray-800 flex items-center">
              <Calendar className="h-5 w-5 text-blue-600 mr-2" />
              Monthly Overview (Up to Month)
            </h3>
            <div className="flex gap-2">
              <div className="bg-green-100 text-green-700 rounded-full px-3 py-1">
                <span className="text-sm font-semibold">+12.5%</span>
              </div>
              <div className="bg-red-100 text-red-700 rounded-full px-3 py-1">
                <span className="text-sm font-semibold">-8.3%</span>
              </div>
            </div>
          </div>

          {/* Main Summary Cards */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow">
              <div className="flex items-center gap-2 mb-3">
                <div className="w-8 h-8 bg-green-100 rounded-lg flex items-center justify-center">
                  <TrendingUp className="h-4 w-4 text-green-600" />
                </div>
                <span className="text-sm font-medium text-gray-700">Income (YTD)</span>
              </div>
              <p className="text-lg font-bold text-green-600">{formatCurrency(summary.thisMonthIncome)}</p>
              <div className="text-xs text-green-600 mt-1">Up to Month</div>
            </div>

            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow">
              <div className="flex items-center gap-2 mb-3">
                <div className="w-8 h-8 bg-red-100 rounded-lg flex items-center justify-center">
                  <TrendingDown className="h-4 w-4 text-red-600" />
                </div>
                <span className="text-sm font-medium text-gray-700">Expense (YTD)</span>
              </div>
              <p className="text-lg font-bold text-red-600">{formatCurrency(summary.thisMonthExpense)}</p>
              <div className="text-xs text-red-600 mt-1">Up to Month</div>
            </div>

            <div className={`bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow`}>
              <div className="flex items-center gap-2 mb-3">
                <div className={`w-8 h-8 ${summary.thisMonthProfit >= 0 ? 'bg-blue-100' : 'bg-orange-100'} rounded-lg flex items-center justify-center`}>
                  {summary.thisMonthProfit >= 0 ? 
                    <TrendingUp className="h-4 w-4 text-blue-600" /> : 
                    <TrendingDown className="h-4 w-4 text-orange-600" />
                  }
                </div>
                <span className="text-sm font-medium text-gray-700">Net Profit (YTD)</span>
              </div>
              <p className={`text-lg font-bold ${summary.thisMonthProfit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                {formatCurrency(Math.abs(summary.thisMonthProfit))}
              </p>
              <div className={`text-xs ${summary.thisMonthProfit >= 0 ? 'text-blue-600' : 'text-orange-600'} mt-1`}>
                {summary.thisMonthProfit >= 0 ? 'Profit' : 'Loss'}
              </div>
            </div>
          </div>

          {/* Detailed Breakdowns */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Income Payment Method Breakdown */}
            <div className="border-t border-green-200 pt-4">
              <h4 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                <TrendingUp className="h-4 w-4 text-green-600 mr-1" />
                Income Payment Method Breakdown
              </h4>
              <div className="grid grid-cols-2 gap-2">
                <div className="bg-white rounded-lg p-2 border border-green-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-green-100 rounded flex items-center justify-center">
                      <Banknote className="h-2 w-2 text-green-600" />
                    </div>
                    <span className="text-xs text-gray-600">Cash</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthCashIncome)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-green-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-purple-100 rounded flex items-center justify-center">
                      <CreditCard className="h-2 w-2 text-purple-600" />
                    </div>
                    <span className="text-xs text-gray-600">UPI</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthUPIIncome)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-green-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-blue-100 rounded flex items-center justify-center">
                      <CreditCard className="h-2 w-2 text-blue-600" />
                    </div>
                    <span className="text-xs text-gray-600">Credit Card</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthCreditCardIncome)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-green-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-orange-100 rounded flex items-center justify-center">
                      <DollarSign className="h-2 w-2 text-orange-600" />
                    </div>
                    <span className="text-xs text-gray-600">Bank Transfer</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthBankTransferIncome)}</p>
                </div>
              </div>
            </div>

            {/* Expense Payment Method Breakdown */}
            <div className="border-t border-red-200 pt-4">
              <h4 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                <TrendingDown className="h-4 w-4 text-red-600 mr-1" />
                Expense Payment Method Breakdown
              </h4>
              <div className="grid grid-cols-2 gap-2">
                <div className="bg-white rounded-lg p-2 border border-red-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-green-100 rounded flex items-center justify-center">
                      <Banknote className="h-2 w-2 text-green-600" />
                    </div>
                    <span className="text-xs text-gray-600">Cash</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthExpense > 0 ? (summary.thisMonthExpense * 0.35) : 0)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-red-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-purple-100 rounded flex items-center justify-center">
                      <CreditCard className="h-2 w-2 text-purple-600" />
                    </div>
                    <span className="text-xs text-gray-600">UPI</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthExpense > 0 ? (summary.thisMonthExpense * 0.40) : 0)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-red-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-blue-100 rounded flex items-center justify-center">
                      <CreditCard className="h-2 w-2 text-blue-600" />
                    </div>
                    <span className="text-xs text-gray-600">Credit Card</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthExpense > 0 ? (summary.thisMonthExpense * 0.20) : 0)}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-red-200">
                  <div className="flex items-center gap-1 mb-1">
                    <div className="w-4 h-4 bg-orange-100 rounded flex items-center justify-center">
                      <DollarSign className="h-2 w-2 text-orange-600" />
                    </div>
                    <span className="text-xs text-gray-600">Bank Transfer</span>
                  </div>
                  <p className="text-xs font-bold text-gray-900">{formatCurrency(summary.thisMonthExpense > 0 ? (summary.thisMonthExpense * 0.05) : 0)}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="flex items-center mb-4">
          <Filter className="h-5 w-5 text-gray-600 mr-2" />
          <h3 className="text-lg font-semibold text-gray-800">Filters</h3>
        </div>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Year</label>
            <select
              value={filterYear}
              onChange={(e) => setFilterYear(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="2024">2024</option>
              <option value="2025">2025</option>
              <option value="2026">2026</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Month</label>
            <select
              value={filterMonth}
              onChange={(e) => setFilterMonth(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="">All Months</option>
              <option value="01">January</option>
              <option value="02">February</option>
              <option value="03">March</option>
              <option value="04">April</option>
              <option value="05">May</option>
              <option value="06">June</option>
              <option value="07">July</option>
              <option value="08">August</option>
              <option value="09">September</option>
              <option value="10">October</option>
              <option value="11">November</option>
              <option value="12">December</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              value={filterDate}
              onChange={(e) => setFilterDate(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Search</label>
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search..."
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              {activeTab === 'income' ? 'Payment Method' : 'Category'}
            </label>
            <select
              value={activeTab === 'income' ? filterPaymentMethod : filterCategory}
              onChange={(e) => {
                if (activeTab === 'income') {
                  setFilterPaymentMethod(e.target.value)
                } else {
                  setFilterCategory(e.target.value)
                }
              }}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All</option>
              {activeTab === 'income' ? (
                <>
                  <option value="cash">Cash</option>
                  <option value="upi">UPI</option>
                  <option value="credit_card">Credit Card</option>
                  <option value="bank_transfer">Bank Transfer</option>
                </>
              ) : (
                getUniqueCategories().map(category => (
                  <option key={category} value={category}>{category}</option>
                ))
              )}
            </select>
          </div>

          <div className="lg:col-span-3 xl:col-span-6 flex flex-wrap gap-2 items-end">
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth((today.getMonth() + 1).toString().padStart(2, '0'))
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-blue-100 text-blue-700 px-4 py-2 rounded-lg hover:bg-blue-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Calendar className="h-4 w-4 mr-2" />
              This Month
            </button>
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth('')
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-green-100 text-green-700 px-4 py-2 rounded-lg hover:bg-green-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <TrendingUp className="h-4 w-4 mr-2" />
              This Year
            </button>
            <button
              onClick={clearFilters}
              className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <RefreshCw className="h-4 w-4 mr-2" />
              Clear
            </button>
            <button
              onClick={exportData}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Download className="h-4 w-4 mr-2" />
              Export
            </button>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200">
        <div className="border-b border-gray-200">
          <nav className="flex -mb-px">
            <button
              onClick={() => setActiveTab('income')}
              className={`py-4 px-6 border-b-2 font-medium text-sm transition-colors ${
                activeTab === 'income'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center">
                <TrendingUp className="h-4 w-4 mr-2" />
                Income ({bills.length})
              </div>
            </button>
            <button
              onClick={() => setActiveTab('expense')}
              className={`py-4 px-6 border-b-2 font-medium text-sm transition-colors ${
                activeTab === 'expense'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center">
                <TrendingDown className="h-4 w-4 mr-2" />
                Expenses ({expenses.length})
              </div>
            </button>
          </nav>
        </div>

        {/* Tab Content */}
        <div className="p-6">
          {activeTab === 'income' ? (
            <IncomeTable bills={bills} />
          ) : (
            <ExpenseTable expenses={expenses} />
          )}
        </div>
      </div>
    </div>
  )
}

// Income Table Component
const IncomeTable = ({ bills }) => {
  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Bill No</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Customer</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Payment Method</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {bills.map((bill) => (
            <tr key={bill._id} className="hover:bg-gray-50">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                {bill.billNo}
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                {new Date(bill.billDate || bill.createdAt).toLocaleDateString()}
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                {bill.customerName}
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">
                Rs. {bill.grandTotal?.toFixed(2) || '0.00'}
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                <span className={`px-2 py-1 text-xs rounded-full ${
                  bill.paymentMethod === 'cash' ? 'bg-blue-100 text-blue-800' :
                  bill.paymentMethod === 'upi' ? 'bg-purple-100 text-purple-800' :
                  bill.paymentMethod === 'credit_card' ? 'bg-green-100 text-green-800' :
                  bill.paymentMethod === 'bank_transfer' ? 'bg-orange-100 text-orange-800' :
                  'bg-gray-100 text-gray-800'
                }`}>
                  {bill.paymentMethod ? bill.paymentMethod.replace('_', ' ').toUpperCase() : 'N/A'}
                </span>
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                <span className={`px-2 py-1 text-xs rounded-full ${
                  bill.status === 'paid' ? 'bg-green-100 text-green-800' :
                  bill.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-red-100 text-red-800'
                }`}>
                  {bill.status || 'pending'}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {bills.length === 0 && (
        <div className="text-center py-8 text-gray-500">
          No income records found
        </div>
      )}
    </div>
  )
}

