import axios from 'axios'

// Use render backend for production, local for development
const API_BASE_URL = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
  ? 'http://localhost:5001/api'
  : 'https://two026backend.onrender.com/api'

const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 60000, // Increased from 30000 to 60000
})

// Add authentication interceptor
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('authToken')
    if (token) {
      config.headers.Authorization = `Bearer ${token}`
    }
    return config
  },
  (error) => {
    return Promise.reject(error)
  }
)

// Add response interceptor for better error handling
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.code === 'ECONNABORTED') {
      console.log('Request timeout, server may be slow to respond')
    } else if (error.response?.status === 503) {
      console.log('Service unavailable (503) - backend server is down')
    } else if (error.response?.status === 404) {
      console.log('API endpoint not found (404)')
    } else if (error.code === 'NETWORK_ERROR') {
      console.log('Network error - check connection')
    }
    return Promise.reject(error)
  }
)

// Add response interceptor for error handling
api.interceptors.response.use(
  (response) => {
    return response
  },
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid, redirect to login
      localStorage.removeItem('authToken')
      localStorage.removeItem('user')
      window.location.href = '/login'
    }
    return Promise.reject(error)
  }
)

