// Customers API
export const customersAPI = {
  getAll: () => api.get('/customers'),
  getById: (id) => api.get(`/customers/${id}`),
  create: (data) => api.post('/customers', data),
  update: (id, data) => api.put(`/customers/${id}`, data),
  delete: (id) => api.delete(`/customers/${id}`),
  uploadPhoto: (id, formData) => {
    const config = {
      headers: {
        'content-type': 'multipart/form-data'
      }
    }
    return api.post(`/customers/${id}/photo`, formData, config)
  },
  updatePhoto: (id, formData) => {
    const config = {
      headers: {
        'content-type': 'multipart/form-data'
      }
    }
    return api.put(`/customers/${id}/photo`, formData, config)
  },
  deletePhoto: (id) => api.delete(`/customers/${id}/photo`),
  // Reminder methods for customers
  addReminder: (customerId, reminderData) => api.post(`/customers/${customerId}/reminders`, reminderData),
  updateReminder: (customerId, reminderId, reminderData) => api.put(`/customers/${customerId}/reminders/${reminderId}`, reminderData),
  deleteReminder: (customerId, reminderId) => api.delete(`/customers/${customerId}/reminders/${reminderId}`),
  updateReminderStatus: (customerId, reminderId, status) => api.patch(`/customers/${customerId}/reminders/${reminderId}/status`, { status })
}

