import React, { useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import Billing from './Billing'
import ExpenseManagement from './ExpenseManagement'
import ProfitLoss from './ProfitLoss'
import IncomeExpense from './IncomeExpense'
import BankingLedger from './BankingLedger'
import ExpenseSettingsWrapper from './ExpenseSettingsWrapper'
import { FileText, IndianRupee, TrendingUp, Receipt, PieChart, DollarSign, Building, Settings, BarChart3 } from 'lucide-react'

const FinancialUnified = () => {
  const [searchParams] = useSearchParams()
  const activeTab = searchParams.get('tab') || 'billing'

  const tabs = [
    { 
      id: 'billing', 
      name: 'Billing', 
      icon: FileText, 
      component: Billing,
      color: 'blue'
    },
    { 
      id: 'expenses', 
      name: 'Expense Management', 
      icon: IndianRupee, 
      component: ExpenseManagement,
      color: 'amber'
    },
    { 
      id: 'income-expense', 
      name: 'Income & Expense', 
      icon: DollarSign, 
      component: IncomeExpense,
      color: 'green'
    },
    { 
      id: 'profit-loss', 
      name: 'Profit & Loss', 
      icon: PieChart, 
      component: ProfitLoss,
      color: 'emerald'
    },
    { 
      id: 'banking-ledger', 
      name: 'Bank', 
      icon: Building, 
      component: BankingLedger,
      color: 'purple'
    },
    { 
      id: 'expense-settings', 
      name: 'Expense Settings', 
      icon: Settings, 
      component: ExpenseSettingsWrapper,
      color: 'rose'
    }
  ]

  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || Billing

  return (
    <div className="h-screen overflow-y-auto p-3 sm:p-4 lg:p-6">
      {/* Tab Navigation */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 mb-6 sm:mb-8 overflow-hidden">
        {/* Mobile Tab Selector */}
        <div className="sm:hidden">
          <select
            value={activeTab}
            onChange={(e) => {
              window.history.pushState({}, '', `/billing?tab=${e.target.value}`)
              window.dispatchEvent(new PopStateEvent('popstate'))
            }}
            className="w-full px-4 py-3 text-sm font-medium text-gray-700 bg-white border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            {tabs.map((tab) => (
              <option key={tab.id} value={tab.id}>
                {tab.name}
              </option>
            ))}
          </select>
        </div>

        {/* Desktop Tab Navigation */}
        <nav className="hidden sm:flex overflow-x-auto overflow-y-hidden">
          {tabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeTab === tab.id
            const getColorClasses = (color) => {
              switch (color) {
                case 'blue':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
                case 'green':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-green-600 to-green-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-green-50 border-r border-gray-200'
                case 'emerald':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-emerald-600 to-emerald-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-emerald-50 border-r border-gray-200'
                case 'amber':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-amber-600 to-amber-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-amber-50 border-r border-gray-200'
                case 'purple':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-purple-600 to-purple-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-purple-50 border-r border-gray-200'
                case 'rose':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-rose-600 to-rose-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-rose-50 border-r border-gray-200'
                case 'slate':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-slate-600 to-slate-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-slate-50 border-r border-gray-200'
                default:
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
              }
            }
            
            return (
              <a
                key={tab.id}
                href={`/billing?tab=${tab.id}`}
                onClick={(e) => {
                  e.preventDefault()
                  window.history.pushState({}, '', `/billing?tab=${tab.id}`)
                  window.dispatchEvent(new PopStateEvent('popstate'))
                }}
                className={`group relative flex items-center flex-shrink-0 px-4 sm:px-6 py-3 sm:py-4 text-xs sm:text-sm font-medium transition-all duration-200 ${getColorClasses(tab.color)}`}
              >
                <div className="relative z-20 flex items-center">
                  <Icon className={`mr-2 sm:mr-3 h-4 w-4 sm:h-5 sm:w-5 transition-colors duration-200 ${
                    isActive ? 'text-white' : 'text-gray-400 group-hover:text-gray-600'
                  }`} />
                  <span className="relative z-20 hidden sm:inline">{tab.name}</span>
                  <span className="relative z-20 sm:hidden text-xs">
                    {tab.name.split(' ')[0]}
                  </span>
                </div>
                {isActive && (
                  <div className={`absolute inset-0 bg-gradient-to-r ${
                    tab.color === 'blue' ? 'from-blue-600 to-indigo-600' :
                    tab.color === 'green' ? 'from-green-600 to-emerald-600' :
                    tab.color === 'amber' ? 'from-amber-600 to-orange-600' :
                    tab.color === 'purple' ? 'from-purple-600 to-pink-600' :
                    tab.color === 'rose' ? 'from-rose-600 to-pink-600' :
                    tab.color === 'slate' ? 'from-slate-600 to-slate-700' :
                    'from-blue-600 to-purple-600'
                  }`}></div>
                )}
                {!isActive && (
                  <div className={`absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r ${
                    tab.color === 'blue' ? 'from-blue-500 to-indigo-500' :
                    tab.color === 'green' ? 'from-green-500 to-emerald-500' :
                    tab.color === 'amber' ? 'from-amber-500 to-orange-500' :
                    tab.color === 'purple' ? 'from-purple-500 to-pink-500' :
                    tab.color === 'rose' ? 'from-rose-500 to-pink-500' :
                    tab.color === 'slate' ? 'from-slate-500 to-slate-600' :
                    'from-blue-500 to-purple-500'
                  } transform scale-x-0 group-hover:scale-x-100 transition-transform duration-200`}></div>
                )}
              </a>
            )
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 sm:p-4 lg:p-6 min-h-[400px] sm:min-h-[500px] lg:min-h-[600px] overflow-x-auto">
        <div className="w-full">
          <ActiveComponent />
        </div>
      </div>
    </div>
  )
}

export default FinancialUnified
