import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'

const AuthGuard = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true)
  const [isAuthenticated, setIsAuthenticated] = useState(false)
  const navigate = useNavigate()

  useEffect(() => {
    // Check if user is authenticated
    const checkAuth = () => {
      const user = localStorage.getItem('user')
      const token = localStorage.getItem('authToken')
      
      console.log('=== AUTH GUARD DEBUG ===')
      console.log('Checking authentication...')
      console.log('User exists:', !!user)
      console.log('Token exists:', !!token)
      console.log('Current path:', window.location.pathname)
      
      if (user && token) {
        try {
          const userData = JSON.parse(user)
          console.log('Parsed user data:', userData)
          
          // Check if user data is valid and has required fields
          if (userData && userData.username && userData.role) {
            // Check if current path is allowed
            const currentPath = window.location.pathname
            const allowedPaths = [
              '/settings', 
              '/customer-management',
              '/reminder-management',
              '/billing',
              '/stock-management',
              '/machines',
              '/financial',
              '/profile'
            ]
            const isAllowedPath = allowedPaths.some(path => currentPath.startsWith(path))
            
            console.log('Allowed paths:', allowedPaths)
            console.log('Is allowed path:', isAllowedPath)
            
            if (isAllowedPath) {
              setIsAuthenticated(true)
              console.log('✅ User is authenticated and path is allowed, allowing access')
            } else {
              console.log('❌ Path not allowed:', currentPath)
              setIsAuthenticated(false)
              console.log('❌ Redirecting to settings page')
              navigate('/settings')
            }
          } else {
            console.log('❌ Invalid user data structure:', userData)
            setIsAuthenticated(false)
            console.log('❌ Invalid user data, redirecting to login')
            navigate('/login')
          }
        } catch (error) {
          console.log('❌ JSON parse error:', error)
          setIsAuthenticated(false)
          console.log('❌ Invalid user data format, redirecting to login')
          navigate('/login')
        }
      } else {
        setIsAuthenticated(false)
        console.log('❌ User not authenticated, redirecting to login')
        navigate('/login')
      }
      
      setIsLoading(false)
    }

    checkAuth()
  }, [navigate])

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl shadow-lg shadow-blue-500/30 mb-4">
            <svg className="animate-spin h-8 w-8 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          </div>
          <p className="text-gray-600">Checking authentication...</p>
        </div>
      </div>
    )
  }

  return isAuthenticated ? children : null
}

export default AuthGuard
