import React, { useState } from 'react'
import { useSearchParams, useNavigate } from 'react-router-dom'
import Machines from './Maintance/Machines'
import Readings from './Maintance/Readings'
import Maintenance from './Maintance/Maintenance'
import { Cpu, BarChart3, Wrench } from 'lucide-react'

const MachinesUnified = () => {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const activeTab = searchParams.get('tab') || 'machines'

  const tabs = [
    { 
      id: 'machines', 
      name: 'Machines', 
      icon: Cpu, 
      component: Machines,
      color: 'blue'
    },
    { 
      id: 'readings', 
      name: 'Readings', 
      icon: BarChart3, 
      component: Readings,
      color: 'green'
    },
    { 
      id: 'maintenance', 
      name: 'Maintenance', 
      icon: Wrench, 
      component: Maintenance,
      color: 'orange'
    }
  ]

  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || Machines

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="p-4 sm:p-6 lg:p-8">
        {/* Tab Navigation */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 mb-4 sm:mb-8 overflow-hidden">
        <nav className="flex overflow-x-auto overflow-y-hidden">
          {tabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeTab === tab.id
            const getColorClasses = (color) => {
              switch (color) {
                case 'blue':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
                case 'green':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-green-600 to-green-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-green-50 border-r border-gray-200'
                case 'orange':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-orange-600 to-orange-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-orange-50 border-r border-gray-200'
                default:
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
              }
            }
            
            return (
              <button
                key={tab.id}
                onClick={() => {
                  navigate(`/machines?tab=${tab.id}`)
                }}
                className={`group relative flex items-center flex-shrink-0 px-3 sm:px-6 py-3 sm:py-4 text-xs sm:text-sm font-medium transition-all duration-200 ${getColorClasses(tab.color)}`}
              >
                <div className="relative z-20 flex items-center">
                  <Icon className={`mr-2 sm:mr-3 h-4 w-4 sm:h-5 sm:w-5 transition-colors duration-200 ${
                    isActive ? 'text-white' : 'text-gray-400 group-hover:text-gray-600'
                  }`} />
                  <span className="relative z-20">{tab.name}</span>
                </div>
                {isActive && (
                  <div className={`absolute inset-0 bg-gradient-to-r ${
                    tab.color === 'blue' ? 'from-blue-600 to-indigo-600' :
                    tab.color === 'green' ? 'from-green-600 to-emerald-600' :
                    tab.color === 'orange' ? 'from-orange-600 to-red-600' :
                    'from-blue-600 to-purple-600'
                  }`}></div>
                )}
                {!isActive && (
                  <div className={`absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r ${
                    tab.color === 'blue' ? 'from-blue-500 to-indigo-500' :
                    tab.color === 'green' ? 'from-green-500 to-emerald-500' :
                    tab.color === 'orange' ? 'from-orange-500 to-red-500' :
                    'from-blue-500 to-purple-500'
                  } transform scale-x-0 group-hover:scale-x-100 transition-transform duration-200`}></div>
                )}
              </button>
            )
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 min-h-[600px]">
        <ActiveComponent />
      </div>
    </div>
    </div>
  )
}

export default MachinesUnified
