import { useState, useEffect } from 'react'
import { Printer, Activity, TrendingUp, AlertTriangle, Calendar, Clock } from 'lucide-react'
import { readingsAPI, machinesAPI, maintenanceAPI } from '../services/api'

const PrinterCard = ({ machineId, showDetails = false }) => {
  const [machine, setMachine] = useState(null)
  const [latestReading, setLatestReading] = useState(null)
  const [maintenanceAlert, setMaintenanceAlert] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (machineId) {
      fetchPrinterData()
    }
  }, [machineId])

  const fetchPrinterData = async () => {
    try {
      // Get machine details
      const machineResponse = await machinesAPI.getById(machineId)
      setMachine(machineResponse.data)

      // Get latest reading for this machine
      const readingsResponse = await readingsAPI.getAll({ machineId })
      const readings = readingsResponse.data
      
      if (readings.length > 0) {
        // Sort by date and get the latest
        const sortedReadings = readings.sort((a, b) => 
          new Date(b.date) - new Date(a.date)
        )
        const latest = sortedReadings[0]
        setLatestReading(latest)

        // Check for maintenance alerts
        const maintenanceResponse = await maintenanceAPI.getAll()
        const maintenanceRecords = maintenanceResponse.data.filter(
          record => record.machineId._id === machineId && record.nextReminderCount
        )

        if (maintenanceRecords.length > 0 && latest) {
          const record = maintenanceRecords[0]
          const currentCount = latest.currentCount
          const reminderCount = record.nextReminderCount

          if (currentCount >= reminderCount) {
            const overCount = currentCount - reminderCount
            setMaintenanceAlert({
              type: 'over',
              priority: overCount > 1000 ? 'high' : 'medium',
              message: `Over by ${overCount.toLocaleString()} prints`,
              serviceType: record.serviceType
            })
          } else if (reminderCount - currentCount <= 1000) {
            const remaining = reminderCount - currentCount
            setMaintenanceAlert({
              type: 'warning',
              priority: remaining <= 100 ? 'high' : 'medium',
              message: `${remaining.toLocaleString()} remaining`,
              serviceType: record.serviceType
            })
          }
        }
      }
    } catch (error) {
      console.error('Error fetching printer data:', error)
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 animate-pulse">
        <div className="h-4 bg-gray-200 rounded mb-2"></div>
        <div className="h-3 bg-gray-100 rounded mb-1"></div>
        <div className="h-3 bg-gray-100 rounded"></div>
      </div>
    )
  }

  if (!machine) {
    return (
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4">
        <div className="text-gray-500 text-sm">Machine not found</div>
      </div>
    )
  }

  const getStatusColor = (status) => {
    switch (status) {
      case 'active': return 'text-green-600 bg-green-50 border-green-200'
      case 'maintenance': return 'text-yellow-600 bg-yellow-50 border-yellow-200'
      case 'inactive': return 'text-red-600 bg-red-50 border-red-200'
      default: return 'text-gray-600 bg-gray-50 border-gray-200'
    }
  }

  const getAlertColor = (priority) => {
    switch (priority) {
      case 'high': return 'text-red-600 bg-red-50 border-red-200'
      case 'medium': return 'text-yellow-600 bg-yellow-50 border-yellow-200'
      default: return 'text-blue-600 bg-blue-50 border-blue-200'
    }
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow">
      {/* Header */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <Printer className="h-5 w-5 text-gray-600" />
          <div>
            <h3 className="font-semibold text-gray-900">{machine.name}</h3>
            <p className="text-xs text-gray-500">{machine.brand}</p>
          </div>
        </div>
        <span className={`text-xs font-medium px-2 py-1 rounded-full border ${getStatusColor(machine.status)}`}>
          {machine.status}
        </span>
      </div>

      {/* Current Count */}
      {latestReading && (
        <div className="space-y-2">
          <div className="flex items-center justify-between bg-blue-50 rounded-lg p-3">
            <div className="flex items-center gap-2">
              <Activity className="h-4 w-4 text-blue-600" />
              <span className="text-sm font-medium text-blue-900">Current Count</span>
            </div>
            <span className="text-lg font-bold text-blue-900">
              {latestReading.currentCount.toLocaleString()}
            </span>
          </div>

          {latestReading.totalPrints > 0 && (
            <div className="flex items-center justify-between bg-green-50 rounded-lg p-2">
              <div className="flex items-center gap-2">
                <TrendingUp className="h-3 w-3 text-green-600" />
                <span className="text-xs text-green-700">Today's Prints</span>
              </div>
              <span className="text-sm font-bold text-green-900">
                {latestReading.totalPrints.toLocaleString()}
              </span>
            </div>
          )}

          <div className="flex items-center justify-between text-xs text-gray-500">
            <div className="flex items-center gap-1">
              <Calendar className="h-3 w-3" />
              <span>{new Date(latestReading.date).toLocaleDateString()}</span>
            </div>
            <div className="flex items-center gap-1">
              <Clock className="h-3 w-3" />
              <span>{new Date(latestReading.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
            </div>
          </div>
        </div>
      )}

      {/* Maintenance Alert */}
      {maintenanceAlert && (
        <div className={`mt-3 p-2 rounded-lg border flex items-center gap-2 ${getAlertColor(maintenanceAlert.priority)}`}>
          <AlertTriangle className="h-4 w-4 flex-shrink-0" />
          <div className="flex-1">
            <div className="text-xs font-medium">{maintenanceAlert.serviceType}</div>
            <div className="text-xs">{maintenanceAlert.message}</div>
          </div>
        </div>
      )}

      {/* No Reading Message */}
      {!latestReading && (
        <div className="text-center py-4 text-gray-500">
          <Printer className="h-8 w-8 mx-auto mb-2 text-gray-300" />
          <p className="text-sm">No readings available</p>
        </div>
      )}

      {/* Additional Details */}
      {showDetails && (
        <div className="mt-3 pt-3 border-t border-gray-200">
          <div className="grid grid-cols-2 gap-2 text-xs">
            <div>
              <span className="text-gray-500">Model:</span>
              <span className="ml-1 font-medium">{machine.model || 'N/A'}</span>
            </div>
            <div>
              <span className="text-gray-500">Location:</span>
              <span className="ml-1 font-medium">{machine.location || 'N/A'}</span>
            </div>
          </div>
          {machine.serialNumber && (
            <div className="mt-2 text-xs">
              <span className="text-gray-500">Serial:</span>
              <span className="ml-1 font-medium">{machine.serialNumber}</span>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default PrinterCard
